import { ZuploRequest, ZuploContext } from "@zuplo/runtime";

/**
 * Recursively converts a JSON object to an XML string.
 * For example: { "user": { "name": "Alice", "role": "admin" } }
 * becomes: <user><name>Alice</name><role>admin</role></user>
 */
function jsonToXml(obj: Record<string, unknown>): string {
  let xml = "";
  for (const [key, value] of Object.entries(obj)) {
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      xml += `<${key}>${jsonToXml(value as Record<string, unknown>)}</${key}>`;
    } else if (Array.isArray(value)) {
      for (const item of value) {
        if (typeof item === "object" && item !== null) {
          xml += `<${key}>${jsonToXml(item as Record<string, unknown>)}</${key}>`;
        } else {
          xml += `<${key}>${escapeXml(String(item))}</${key}>`;
        }
      }
    } else {
      xml += `<${key}>${escapeXml(String(value))}</${key}>`;
    }
  }
  return xml;
}

/**
 * Escapes special XML characters in a string.
 */
function escapeXml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

/**
 * Inbound policy that intercepts the request, reads the JSON body,
 * converts it to XML, and forwards the transformed request.
 */
export async function jsonToXmlInboundPolicy(
  request: ZuploRequest,
  context: ZuploContext
): Promise<ZuploRequest> {
  // Read the JSON body from the original request
  const jsonBody = await request.json();

  // Convert JSON to XML
  const xmlBody = jsonToXml(jsonBody as Record<string, unknown>);

  context.log.info(`Transformed JSON to XML: ${xmlBody}`);

  // Create a new Request with the XML body and updated Content-Type header
  const newRequest = new ZuploRequest(request, {
    body: xmlBody,
    headers: {
      "content-type": "application/xml",
      "content-length": String(new TextEncoder().encode(xmlBody).length),
    },
  });

  return newRequest;
}

import { ZuploRequest, ZuploContext } from "@zuplo/runtime";

/**
 * Echo handler that reads the request body as text and returns it in a Response.
 */
export async function echoHandler(
  request: ZuploRequest,
  context: ZuploContext
): Promise<Response> {
  const body = await request.text();

  return new Response(body, {
    status: 200,
    headers: {
      "content-type": "text/plain",
    },
  });
}

